mapper.select:
SELECT cm.id, cm.game_type as gameType, cm.card_name as cardName, cm.card_number as cardNumber, cm.rarity, cm.language, cm.manufacturer, cm.image_url as imageUrl, cm.description, cm.is_active as isActive, cm.pokemon_id as pokemonId, cm.hp, cm.evolution_stage as evolutionStage, cs.id as cardSetId, cs.name as cardSetName, cc.id as categoryId, cc.display_name as categoryName, et.id as elementalTypeId, et.display_name as elementalTypeName FROM card_master cm LEFT JOIN card_set cs ON cm.card_set_id = cs.id LEFT JOIN card_category cc ON cm.category_id = cc.id LEFT JOIN elemental_type et ON cm.elemental_type_id = et.id
cm.is_active = true
AND cm.game_type = #{gameType}
AND cm.card_name LIKE CONCAT('%', #{cardName}, '%')
AND cm.card_set_id = #{cardSetId}
AND cm.card_number = #{cardNumber}
AND cm.rarity = #{rarity}
AND cm.category_id = #{categoryId}
AND cm.elemental_type_id = #{elementalTypeId}
AND cm.evolution_stage = #{evolutionStage}
